"use client";
import { useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";

export default function RegisterPage() {
  const [name, setName] = useState("");
  const [user, setUser] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [jobTitle, setJobTitle] = useState("");
  const [showPassword, setShowPassword] = useState(false); // สถานะแสดง/ซ่อนรหัสผ่าน
  const router = useRouter();

  const isPasswordValid = password.length >= 8;
  const showPasswordError = password.length > 0 && !isPasswordValid;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isPasswordValid) return;

    const res = await fetch("/api/register", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name, user, email, password, jobTitle })
    });

    if (res.ok) {
      alert("ลงทะเบียนสำเร็จ");
      router.push("/login");
    } else {
      const data = await res.json();
      alert(data.error);
    }
  };

  return (
    <main style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#f0f9ff', padding: '20px' }}>
      <section className="card" style={{ width: '100%', maxWidth: '450px', padding: '40px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.05)', textAlign: 'center' }}>
        <h1 style={{ fontSize: '32px', color: '#1e293b', marginBottom: '30px' }}>สมัครสมาชิก</h1>

        <form onSubmit={handleSubmit} style={{ textAlign: 'left', display: 'flex', flexDirection: 'column', gap: '15px' }}>
          <input
            type="text" placeholder="ชื่อ-นามสกุล"
            style={{ width: '100%', padding: '12px 15px', borderRadius: '12px', border: '1px solid #e2e8f0' }}
            value={name} onChange={(e) => setName(e.target.value)} required
          />
          <input
            type="email" placeholder="อีเมลส่วนตัว"
            style={{ width: '100%', padding: '12px 15px', borderRadius: '12px', border: '1px solid #e2e8f0' }}
            value={email} onChange={(e) => setEmail(e.target.value)} required
          />
          <input
            type="text" placeholder="ตำแหน่งงาน"
            style={{ width: '100%', padding: '12px 15px', borderRadius: '12px', border: '1px solid #e2e8f0' }}
            value={jobTitle} onChange={(e) => setJobTitle(e.target.value)}
          />

          <div style={{ margin: '10px 0', borderBottom: '1px solid #f1f5f9' }}></div>

          <input
            type="text" placeholder="User (สำหรับเข้าสู่ระบบ)"
            style={{ width: '100%', padding: '12px 15px', borderRadius: '12px', border: '1px solid #e2e8f0', background: '#f8fafc' }}
            value={user} onChange={(e) => setUser(e.target.value)} required
          />

          {/* ช่องรหัสผ่านพร้อมระบบแสดง/ซ่อน */}
          <div style={{ position: 'relative' }}>
            <input
              type={showPassword ? "text" : "password"} // สลับ Type ตามสถานะ
              placeholder="รหัสผ่าน (8 ตัวขึ้นไป)"
              style={{
                width: '100%', padding: '12px 45px 12px 15px', borderRadius: '12px',
                border: `1px solid ${showPasswordError ? '#ef4444' : '#e2e8f0'}`,
                background: '#f8fafc', outline: 'none'
              }}
              value={password} onChange={(e) => setPassword(e.target.value)} required
            />
            {/* ปุ่มรูปดวงตาแบบ Inline */}
            {/* ปุ่มรูปดวงตาดีไซน์มินิมอล */}
            <button
              type="button"
              onClick={() => setShowPassword(!showPassword)}
              style={{
                position: 'absolute', right: '15px', top: '50%', transform: 'translateY(-50%)',
                background: 'none', border: 'none', cursor: 'pointer', padding: 0,
                display: 'flex', alignItems: 'center', color: '#64748b'
              }}
            >
              {showPassword ? (
                // ไอคอนตาเปิด (Show)
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path>
                  <circle cx="12" cy="12" r="3"></circle>
                </svg>
              ) : (
                // ไอคอนตามีขีดฆ่า (Hide)
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"></path>
                  <line x1="1" y1="1" x2="23" y2="23"></line>
                </svg>
              )}
            </button>
            {showPasswordError && (
              <p style={{ color: '#ef4444', fontSize: '12px', marginTop: '5px', marginLeft: '5px' }}>
                รหัสผ่านต้องมีความยาวอย่างน้อย 8 ตัวอักษร
              </p>
            )}
          </div>

          <button
            type="submit"
            disabled={!isPasswordValid && password.length > 0}
            className="btn"
            style={{
              width: '100%', padding: '14px', borderRadius: '12px',
              background: isPasswordValid ? '#0ea5e9' : '#cbd5e1',
              color: 'white', fontWeight: '600', border: 'none',
              cursor: isPasswordValid ? 'pointer' : 'not-allowed', marginTop: '10px'
            }}
          >
            ลงทะเบียน
          </button>
        </form>

        <footer style={{ marginTop: '25px' }}>
          <p style={{ fontSize: '14px', color: '#64748b' }}>
            มีบัญชีผู้ใช้งานแล้วใช่หรือไม่? <Link href="/login" style={{ color: '#0ea5e9', fontWeight: '600', textDecoration: 'none' }}>เข้าสู่ระบบที่นี่</Link>
          </p>
        </footer>
      </section>
    </main>
  );
}